# DK SBS.  Skanderborg - Skjern
#
let ss = path("d3.dk.sbs");

with detail = 3,
     railway = :first :pax
{
    # point.dk.Skanderborg  dk.FFH

    with link = "line.dk.SBS" {
        track(:lor,
                ss[:ska.ys - 0.1dl, :ska.ys] >> 0.5md >> 1ms >> 0.5mt
            ..  ss[:ska.xs + 2md, :ska.xs + 2.1md]
        );
        track(ss[:ska.xs + 2md, :ska.ys + 2.5km]);
        line_label(:right:s, ss[:ska.ys + 2.5km] >> 0.5mt,
            (0.3dt, 0dt), "SBS"
        );
        track(ss[:ska.ys + 2.5km, :alk - 0.49sw]);
    }

    with link = "point.dk.Alken", railway = :station {
        track(ss[:alk - 0.5sw, :alk + 0.5sw]);
        marker(:right :de.hp, ss[:alk] >> 0.5mt);
        marker(:right :de.exbf, ss[:alk] >> 0.5mt);
        slabel(:top, ss[:alk] >> 0.5mt >> 1.4sh >> 0.3dt, "Alken");
    }

    with link = "line.dk.SBS" {
        track(ss[:alk + 0.49sw, :ryy - 0.49sw]);
    }

    with link = "point.dk.Ry", railway = :station {
        track(ss[:ryy - 0.5sw, :ryy + 0.5sw]);
        marker(:left :de.bf, ss[:ryy] << 0.5mt);
        slabel(:left, ss[:ryy] << 0.5mt << 1sh + (-1.5dt, 1.3dt), "Ry");
    }

    with link = "line.dk.SBS" {
        track(ss[:ryy + 0.49sw, :all - 0.49sw]);
    }

    with link = "point.dk.Alling", railway = :station {
        track(ss[:all - 0.5sw, :all + 0.5sw]);
        marker(:left :de.hp :removed, ss[:all] << 0.5mt);
        slabel(:left :removed, ss[:all] << 0.5mt << 1sh + (-1.3dt, 1dt),
            "Alling"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:all + 0.49sw, :lav - 0.49sw]);
    }

    with link = "point.dk.Laven", railway = :station {
        track(ss[:lav - 0.5sw, :lav + 0.5sw]);
        marker(:right :de.bf, ss[:lav] >> 0.5mt);
        slabel(:top, ss[:lav] >> 0.5mt >> 1sh >> 0.3dt, "Laven");
    }

    with link = "line.dk.SBS" {
        track(ss[:lav + 0.49sw, :sve - 0.49sw]);
    }

    with link = "point.dk.Svejbæk", railway = :station {
        track(ss[:sve - 0.5sw, :sve + 0.5sw]);
        marker(:left :de.bf, ss[:sve] << 0.5mt);
        slabel(:left, ss[:sve] << 0.5mt << 1sh + (-1.8dt, 1.3dt), "Svejbæk");
    }

    with link = "line.dk.SBS" {
        track(ss[:sve + 0.49sw, :sve + 1.51km]);
        line_label(:right:sw, ss[:sve + 1.5km] >> 0.5mt, "SBS");
        track(ss[:sve + 1.49km, :sej - 0.49sw]);
    }

    with link = "point.dk.Sejs", railway = :station {
        track(ss[:sej - 0.5sw, :sej + 0.5sw]);
        marker(:left :de.hp :removed, ss[:sej] << 0.5mt);
        slabel(:left :removed, ss[:sej] << 0.5mt << 1sh + (-1.8dt, 1.3dt),
            "Sejs"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:sej + 0.49sw, :sil.yl - 0.49seg]);
    }

    with link = "point.dk.Silkeborg", railway = :station {
        track(:removed,
                ss[:sil - 0.5sw - 1.1dl, :sil - 0.5sw - 1ld]
            --  ss[:sil - 0.5sw, :sil.yh] << 1ms << 1mt
        );
        track(ss[:sil.yl - 0.5seg, :sil.yh + 0.5seg]);
        track(:removed, ss[:sil.yl, :sil.yh] >> 1ms >> 1mt);
        marker(:right :de.bf, ss[:sil] >> 1ms >> 1.5mt);
        slabel(:top :bold, ss[:sil] >> 1ms >> 1.5mt >> 1sh >> 0.2dt,
            "Silkeborg"
        );
    }

    with link = "line.dk.SBS" {
        track(:ror, ss[:sil.yh + 0.49sw, :sil.yr]);
        track(:ror, ss[:sil.yr - 0.1dl, :sil.yr + 1seg]);
        track(ss[:sil.yr + 0.99seg, :sil.yr + 1.41km]);
        line_label(:right:se, ss[:sil.yr + 1.4km] >> 0.5mt, "SBS");
        track(ss[:sil.yr + 1.39km, :fun - 0.49sw - 2dl]);
    }

    with link = "point.dk.Funder", railway = :station {
        track(ss[:fun - 0.5sw - 2dl, :fun + 0.5sw]);
        track(:removed,
                ss[:fun - 0.5sw - 1.1dl, :fun - 0.5sw - 1dl]
            --  ss[:fun - 0.5sw, :fun + 0.5sw] >> 1ms >> 1mt
        );
        marker(:right :de.bbf :nopax, ss[:fun] >> 1ms >> 1.5mt);
        marker(:right :de.exbf :nopax, ss[:fun] >> 1ms >> 1.5mt);
        slabel(:left :bold :nopax,
            ss[:fun] >> 1ms >> 1.5mt >> 1.4sh + (-1.6dt, 0.8dt),
            "Funder"
        );
    }

    with link = "line.dk.SBS" {
        track(:ror, ss[:fun + 0.49sw, :fun.yb]);
        with layer = -1 track(:ror, ss[:fun.yb - 0.1dl, :fun.yb + 1seg]);
        with layer = -1 track(ss[:fun.yb + 0.9seg, :fun.yb + 3.31km]);
        line_label(:right:sw, ss[:fun.yb + 3.3km] >> 0.5mt, "SBS");
        track(ss[:fun.yb + 3.29km, :mos - 0.49sw]);
    }

    with link = "point.dk.Moselund", railway = :station {
        track(ss[:mos - 0.5sw, :mos + 0.5sw]);
        marker(:left :de.bf :removed, ss[:mos] << 0.5mt);
        slabel(:right :removed, ss[:mos - 0.5sw] >> 0.5mt + (0.8dt, -0.3dt),
            "Moselund"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:mos + 0.49sw, :eng - 0.49sw]);
    }

    with link = "point.dk.Engesvang", railway = :station {
        track(ss[:eng - 0.5sw, :eng + 0.5sw]);
        marker(:right :de.bf, ss[:eng] >> 0.5mt);
        slabel(:top, ss[:eng] >> 0.5mt >> 1sh + (-2dt, -0.5dt), "Engesvang");
    }

    with link = "line.dk.SBS" {
        track(ss[:eng + 0.49sw, :bod - 0.49sw]);
    }

    with link = "point.dk.Bording", railway = :station {
        track(ss[:bod - 0.5sw, :bod + 0.5sw]);
        marker(:right :de.bf, ss[:bod] >> 0.5mt);
        slabel(:top, ss[:bod] >> 0.5mt >> 1sh + (0.3dt, -0.3dt), "Bording");
    }

    with link = "line.dk.SBS" {
        track(ss[:bod + 0.49sw, :ika - 0.49sw]);
    }

    with link = "point.dk.Ikast", railway = :station {
        track(ss[:ika - 0.5sw, :ika + 0.5sw]);
        marker(:left :de.bf, ss[:ika] << 0.5mt);
        slabel(:bottom, ss[:ika] << 0.5mt << 1sh + (-0.5dt, 0.4dt), "Ikast");
    }

    with link = "line.dk.SBS" {
        track(ss[:ika + 0.49sw, :ika + 4.01km]);
        line_label(:right:s, ss[:ika + 4km] >> 0.5mt, "SBS");
        track(ss[:ika + 3.99km, :ham - 0.49sw]);
    }

    with link = "point.dk.Hammerum", railway = :station {
        track(ss[:ham - 0.5sw, :ham + 0.5sw]);
        marker(:right :de.bf, ss[:ham] >> 0.5mt);
        slabel(:right, ss[:ham] << 0.5mt + (1.5dt, 1.5dt), "Hammerum");
    }

    with link = "line.dk.SBS" {
        track(ss[:ham + 0.49sw, :bir - 0.49sw]);
    }

    with link = "point.dk.Birk-Centerpark", railway = :station {
        track(ss[:bir - 0.5sw, :bir + 0.5sw]);
        marker(:right :de.hp, ss[:bir] >> 0.5mt);
        slabel(:top, ss[:bir] >> 0.5mt >> 1sh + (0.4dt, -0.5dt),
            vbox(:center:base, "Birk", "Centerpark")
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:bir + 0.49sw, :her.xs]);
    }

    # point.dk.Herning  dk.HBV

    with link = "line.dk.SBS" {
        track(
                ss[:her.yh + 0.49seg, :her.yh + 1seg] << 1ms << 1mt
            ..  ss[:hme - 0.5sw, :hme - 0.49sw]
        );
    }

    with link = "point.dk.Herning-Messecenter", railway = :station {
        track(ss[:hme - 0.5sw, :hme + 0.5sw]);
        marker(:left :de.hp, ss[:hme] << 0.5mt);
        slabel(:left, ss[:hme] >> 0.5mt + (-1dt, 0.4dt),
            "Herning Messecenter"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:hme + 0.49sw, :hme + 2.01km]);
        line_label(:left:nw, ss[:hme + 2km] << 0.5mt, "SBS");
        track(ss[:hme + 1.99km, :stu - 0.49sw]);
    }

    with link = "point.dk.Studsgård", railway = :station {
        track(ss[:stu - 0.5sw, :stu + 0.5sw]);
        marker(:right :de.hp, ss[:stu] >> 0.5mt);
        marker(:right :de.exbf, ss[:stu] >> 0.5mt);
        slabel(:left, ss[:stu] >> 0.5mt >> 1.4sh + (-1.4dt, 0.8dt),
            "Studsgård"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:stu + 0.49sw, :kib - 0.49sw]);
    }

    with link = "point.dk.Kibæk", railway = :station {
        track(ss[:kib - 0.5sw, :kib + 0.5sw]);
        marker(:right :de.bf, ss[:kib] >> 0.5mt);
        slabel(:top, ss[:kib] >> 0.5mt >> 1sh + (-1.5dt, -0.5dt),
            "Kibæk"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:kib + 0.49sw, :kib + 4.01km]);
        line_label(:right:se, ss[:kib + 4km] >> 0.5mt, "SBS");
        track(ss[:kib + 3.99km, :tro - 379m]);
    }

    with link = "point.dk.Troldhede", railway = :station {
        # DK THK
        track(:removed,
                ss[:tro - 351m, :tro - 350m]
            --  ss[:tro - 350m + 1dl, :tro.yk] << 1ms << 1mt
        );

        # DK SBS
        track(ss[:tro - 380m, :tro.yk + 1seg]);

        marker(:right :de.hp, ss[:tro] >> 0.5mt);
        marker(:right :de.exbf, ss[:tro] >> 0.5mt);
        slabel(:left :bold, ss[:tro] >> 0.5mt >> 1.4sh + (-1.5dt, 0.5dt),
            "Troldhede"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:tro.yk + 0.99seg, :bos - 0.49sw]);
    }

    with link = "point.dk.Borris", railway = :station {
        track(ss[:bos - 0.5sw, :bos + 0.5sw]);
        marker(:right :de.bf, ss[:bos] >> 0.5mt);
        slabel(:top, ss[:bos] >> 0.5mt >> 1sh + (-1.5dt, -0.4dt),
            "Borris"
        );
    }

    with link = "line.dk.SBS" {
        track(ss[:bos + 0.49sw, :bos + 4.01km]);
        line_label(:left:n, ss[:bos + 4km] << 0.5mt, (0.3dt, 0dt), "SBS");
        track(ss[:bos + 3.99km, :ske.xs - 2mt]);
        track(:lor,
                ss[:ske.xs - 2.1mt, :ske.xs - 2mt]
            ..  ss[:ske.ys, :ske.ys + 0.1dl] >> 1ms >> 1mt
        );
    }

    # point.dk.Skjern  dk.LES
}

